{/* Mock Test Page */}
{page === 'test' && (
  <div className="card">
    <h2>{t.topicLabel}</h2>

    <div className="topic-row">
      <input
        value={topic}
        onChange={(e) => setTopic(e.target.value)}
        placeholder={t.topicPlaceholder}
        className="topic-input"
      />

      <select
        value={numQuestions}
        onChange={(e) => setNumQuestions(e.target.value)}
        className="num-select"
      >
        <option value={5}>5 Questions</option>
        <option value={10}>10 Questions</option>
        <option value={15}>15 Questions</option>
        <option value={20}>20 Questions</option>
      </select>

      <button
        onClick={generateMCQs}
        disabled={testLoading}
        className={`ask-btn ${testLoading ? 'disabled' : ''}`}
      >
        {testLoading ? t.generating : t.generateBtn}
      </button>
    </div>

    {mcqs.length > 0 && (
      <div className="mcq-list">
        {mcqs.map((mcq, i) => (
          <div key={i} className="mcq-item">
            <p className="mcq-question">
              {i + 1}. {mcq.question}
            </p>

            <div className="options">
              {mcq.options.map((opt, j) => (
                <button
                  key={j}
                  className={`option-btn ${
                    selected[i] === opt ? 'selected' : ''
                  } ${
                    score !== null
                      ? opt === mcq.answer
                        ? 'correct'
                        : selected[i] === opt
                        ? 'wrong'
                        : ''
                      : ''
                  }`}
                  onClick={() => {
                    if (score === null) {
                      setSelected({ ...selected, [i]: opt });
                    }
                  }}
                >
                  {opt}
                </button>
              ))}
            </div>
          </div>
        ))}

        {score === null ? (
          <button
            onClick={submitTest}
            className="ask-btn"
            style={{ marginTop: '20px' }}
          >
            {t.submitBtn}
          </button>
        ) : (
          <div className="score-box">
            <h2>
              {t.scoreText}: {score} / {mcqs.length}{' '}
              {score === mcqs.length
                ? '🎉'
                : score >= 3
                ? '👍'
                : '💪'}
            </h2>

            <button
              onClick={() => {
                setMcqs([]);
                setSelected({});
                setScore(null);
                setTopic('');
              }}
              className="ask-btn"
            >
              {t.retryBtn}
            </button>
          </div>
        )}
      </div>
    )}
  </div>
)}
